 namespace WPAICG\Core; if (!defined('ABSPATH')) { exit; } class AIPKit_Event_Registry { public const SCHEMA_VERSION = '2026-05-21'; public static function get_definitions(): array { return [ 'chatbot.session_started' => [ 'module' => 'chatbot', 'category' => 'chatbot', 'label' => 'Chat Session Started', ], 'chatbot.user_message_submitted' => [ 'module' => 'chatbot', 'category' => 'chatbot', 'label' => 'Chat User Message Submitted', ], 'chatbot.response_generated' => [ 'module' => 'chatbot', 'category' => 'chatbot', 'label' => 'Chat Response Generated', ], 'chatbot.fb_submitted' => [ 'module' => 'chatbot', 'category' => 'chatbot', 'label' => 'Chat Feedback Submitted', ], 'chatbot.form_submitted' => [ 'module' => 'chatbot', 'category' => 'chatbot', 'label' => 'Chatbot Form Submitted', ], 'content.generated' => [ 'module' => 'content_writer', 'category' => 'content', 'label' => 'Content Generated', ], 'task.item_completed' => [ 'module' => 'automated_tasks', 'category' => 'tasks', 'label' => 'Task Queue Item Completed', ], 'form.submitted' => [ 'module' => 'ai_forms', 'category' => 'forms', 'label' => 'AI Form Submitted', ], 'image.generated' => [ 'module' => 'image_generator', 'category' => 'images', 'label' => 'Image Generated', ], 'kb.source_indexed' => [ 'module' => 'knowledge_base', 'category' => 'knowledge_base', 'label' => 'KB Source Indexed', ], ]; } public static function has_event(string $event_name): bool { $definitions = self::get_definitions(); return isset($definitions[$event_name]); } public static function get_definition(string $event_name): ?array { $definitions = self::get_definitions(); return $definitions[$event_name] ?? null; } public static function get_schema_version(): string { return self::SCHEMA_VERSION; } } 